/* ============ RANKING VIVO (NPCs) ============ */
function pointsFromRank(r){
  if(r<=1) return 11500;
  for(let i=0;i<RANK_ANCH.length-1;i++){
    const [p1,r1]=RANK_ANCH[i],[p2,r2]=RANK_ANCH[i+1];
    if(r>=r1 && r<=r2){
      const f=(Math.log(r)-Math.log(r1))/(Math.log(r2)-Math.log(r1));
      return Math.max(2,Math.round(Math.exp(Math.log(p1)+f*(Math.log(Math.max(p2,0.5))-Math.log(p1)))));
    }
  }
  return 2;
}
function buildLadder(){
  const npcs=[];
  for(let i=1;i<=1500;i++){
    let name,co;
    if(i<=REAL_PLAYERS.length){ name=REAL_PLAYERS[i-1][0]; co=REAL_PLAYERS[i-1][1]; }
    else {
      name=FIRST_NAMES.default[ri(0,FIRST_NAMES.default.length-1)]+" "+LAST_NAMES[ri(0,LAST_NAMES.length-1)];
      co=COUNTRIES[ri(0,COUNTRIES.length-1)][0];
    }
    npcs.push([name,co,Math.max(2,Math.round(pointsFromRank(i)*rnd(.97,1.03)))]);
  }
  npcs.sort((a,b)=>b[2]-a[2]);
  return npcs;
}
function updateLadder(){
  // resultados da semana: cada jogador defende/ganha pontos
  G.npcs.forEach(n=>{ n[2]=Math.max(1,Math.round(n[2]*0.9815 + n[2]*0.019*rnd(0,2))); });
  G.npcs.sort((a,b)=>b[2]-a[2]);
}

