function buildReport(pts, prize){
  const wins=T.matches.filter(m=>m.res.won);
  const last=T.matches[T.matches.length-1];
  let h;
  if(T.champion)
    h=`<h2 class="gold">🏆 Campeão do ${T.t.name}!</h2><p style="margin:8px 0">Semana perfeita em ${T.t.city}: ${wins.length} vitórias e o troféu na mala.</p>`;
  else if(wins.length===0)
    h=`<h2>📋 Resumo da semana</h2><p style="margin:8px 0">Semana curta em ${T.t.city}: eliminado na estreia (${last.rn}) por ${last.opp.name} (#${last.opp.rank}), parciais de ${last.res.score}.</p>`;
  else
    h=`<h2>📋 Resumo da semana</h2><p style="margin:8px 0">Boa campanha no ${T.t.name}: ${wins.length} vitória(s) até cair na ${last.rn} diante de ${last.opp.name} (#${last.opp.rank}).</p>`;
  if(wins.length){
    const best=wins.reduce((a,m)=>m.opp.rank<a.opp.rank?m:a);
    h+=`<p class="small">Melhor vitória: ${best.opp.name} (#${best.opp.rank}).</p>`;
  }
  h+=`<p style="margin-top:6px">Saldo: <b class="blue">+${pts} pontos</b> · <b class="gold">${fmt$(prize)}</b> de premiação.</p>`;
  if(G.injury>0) h+=`<p class="small red" style="margin-top:6px">🤕 Você saiu lesionado — ${G.injury} semana(s) de recuperação.</p>`;
  else if(G.energy<35) h+=`<p class="small red" style="margin-top:6px">⚠️ Você terminou a semana desgastado — considere descansar.</p>`;
  return h;
}

