    if(e.ok && !e.useWc && myR<=c.worst*1.15 && o2<best2){best2=o2;pick=i;} });
  if(pick<0){ list.forEach((t,i)=>{ const e=canEnter(t); if(e.ok && !e.useWc && pick<0) pick=i; }); }
  if(pick<0){ doTraining(); continue; }
