console.log("bloqueios por falta de fundos:",brokeBlocks,"| W/L:",G.wins+"/"+G.losses,"| titulos:",G.titles.length,"| melhor rank:",G.bestRank);
if(firstOfferWeek<0||firstOfferWeek>8) throw new Error("primeira proposta nao chegou cedo");
if(contractsSigned===0) throw new Error("nenhum contrato assinado");
